705	
706	
707	    // Toca a música de fundo
708	    g_BGMHandle = g_BusMusic.play(musicaDeFundo);
709	
710	    // CONFIGURAÇÃO DE ATENUAÇÃO 3D (VOLUME A DISTÂNCIA)
711	    // O parâmetro LINEAR_DISTANCE força o volume a cair até 0% no MaxDistance.
712	    // O segundo parâmetro (1.0f) é o fator de rolloff (caída padrão).
713	    
714	    g_SfxButton.set3dAttenuation(SoLoud::AudioSource::LINEAR_DISTANCE, 0.75f);
715	    g_SfxButton.set3dMinMaxDistance(1.0f, 10.0f);
716	    g_SfxButtonUp.set3dAttenuation(SoLoud::AudioSource::LINEAR_DISTANCE, 0.75f);
717	    g_SfxButtonUp.set3dMinMaxDistance(1.0f, 10.0f);
718	    g_SfxDoor.set3dAttenuation(SoLoud::AudioSource::LINEAR_DISTANCE, 0.75f);
719	    g_SfxDoor.set3dMinMaxDistance(1.0f, 10.0f);
720	    g_SfxDoorClose.set3dAttenuation(SoLoud::AudioSource::LINEAR_DISTANCE, 0.75f);
721	    g_SfxDoorClose.set3dMinMaxDistance(1.0f, 10.0f);
722	
723	    // Inicializamos ultimoFrame aqui para evitar um deltaTime gigante no primeiro
724	    // frame (o carregamento dos assets leva vários segundos, e ultimoFrame = 0
725	    // causaria gravidade acumulada suficiente para teleportar o jogador para -∞)
726	    ultimoFrame = (float)glfwGetTime();
727	
728	    // Ficamos em um loop infinito, renderizando, até que o usuário feche a janela
729	    while (!glfwWindowShouldClose(window))
730	    {
731	        // Aqui executamos as operações de renderização
732	
733	        // Cálculos de tempo
734	        float atualFrame = (float)glfwGetTime();
735	        deltaTime = atualFrame - ultimoFrame;
