#define RADIO_BASE_PART 33
#define CAKE 34
#define CAKE_CANDLE 35
#define CAKE_CHERRY 36
#define CAKE_CHERRY_CREAM 37
#define CAKE_BOTTOM 38

// Constantes
#ifndef M_PI
#define M_PI   3.14159265358979323846
#endif

#ifndef M_PI_2
#define M_PI_2 1.57079632679489661923
