549	        vec3 light_dir = LIGHT_POSITIONS[i] - p.xyz;
550	        float dist = length(light_dir); // Distância até a luz
551	        vec3 l = normalize(light_dir);
552	
553	        // Atenuação: a luz perde força conforme chega no chão ou no meio da sala
554	        // Fraca/original, caso queiramos comparar:
555	        // float attenuation = 1.0 / (1.0 + 0.09 * dist + 0.04 * (dist * dist));
556	
557	        // Forte/nova: A luz perde força rapidamente, criando cantos escuros.
558	        float attenuation = 1.0 / (1.0 + 0.14 * dist + 0.07 * (dist * dist));
559	
560	        // Termo Difuso (Lambert)
561	        float lambert = max(0.0, dot(n.xyz, l));
562	        vec3 diffuse = Kd0 * LIGHT_COLORS[i] * lambert;
563	
564	        // Termo Especular (Blinn-Phong)
565	        vec3 h = normalize(v.xyz + l);
566	        float n_dot_h = max(0.0, dot(n.xyz, h));
567	        float shininess = mix(32.0, 64.0, metalness); 
568	        float specular_intensity = pow(n_dot_h, shininess);
569	
570	        // O metal pinta o reflexo com a cor da própria textura (Kd0)
571	        vec3 base_specular_color = mix(vec3(1.0), Kd0, metalness);
572	        
573	        // O metal brilha mais forte com as luzes
574	        float metal_boost = mix(1.0, 3.0, metalness);
575	
576	        float current_ks = Ks_map;
577	        // Se for uma peça do rádio e não tiver Ks_map definido, damos um brilho base de 0.3
578	        if (object_id >= RADIO_SHELL && object_id <= RADIO_BASE_PART && Ks_map == 0.0) {
579	            current_ks = 0.3; 
580	        }
581	
582	        vec3 specular = base_specular_color * LIGHT_COLORS[i] * specular_intensity * current_ks * metal_boost;
583	
584	        // vec3 specular = vec3(1.0) * LIGHT_COLORS[i] * specular_intensity * Ks_map; // Antigo
585	
586	        // Somamos a contribuição dessa luz com a atenuação aplicada
587	        total_diffuse += diffuse * attenuation;
588	        total_specular += specular * attenuation;
