601	        vec3 D_spot = normalize(flashlight_dir.xyz);
602	        
603	        // Cálculo do ângulo do cone (o dot product compara a luz com o centro do cone)
604	        float cos_theta = dot(-L_spot, D_spot);
605	        float cos_cutoff = cos(radians(25.0)); // 25 graus de abertura
606	        
607	        if (cos_theta > cos_cutoff) {
608	            // Atenuação por distância (para não iluminar o mundo todo)
609	            float dist = length(flashlight_pos.xyz - p.xyz);
610	            float attenuation = 1.0 / (1.0 + 0.1 * dist + 0.01 * (dist * dist));
611	            
612	            // Intensidade baseada no ângulo (suaviza as bordas do cone)
613	            float epsilon = 0.05;
614	            float spot_intensity = smoothstep(cos_cutoff, cos_cutoff + epsilon, cos_theta);
615	            
616	            final_flashlight = Kd0 * flashlight_color * attenuation * spot_intensity;
617	        }
618	    }
